/* CSS Variables */
:root {
    /* Colors */
    --color-primary: #6F4E37;
    --color-primary-dark: #483223;
    --color-primary-light: #8B6B4F;
    --color-accent: #C4A77D;
    --color-accent-light: #D4B88A;
    --color-bg: #FFFDF8;
    --color-bg-alt: #F9F6F1;
    --color-text: #2C2420;
    --color-text-light: #6B5D54;
    --color-text-muted: #9A8B80;
    --color-white: #FFFFFF;
    --color-border: #E8E2D9;

    /* Gradients */
    --gradient-warm: linear-gradient(135deg, #6F4E37 0%, #8B6B4F 100%);
    --gradient-accent: linear-gradient(135deg, #C4A77D 0%, #D4B88A 100%);
    --gradient-hero: linear-gradient(135deg, rgba(72, 50, 35, 0.92) 0%, rgba(111, 78, 55, 0.88) 100%);

    /* Typography */
    --font-heading: 'Playfair Display', Georgia, serif;
    --font-body: 'Inter', -apple-system, sans-serif;

    /* Spacing */
    --section-padding: 7rem;
    --container-width: 1280px;

    /* Shadows */
    --shadow-sm: 0 2px 8px rgba(44, 36, 32, 0.06);
    --shadow-md: 0 4px 20px rgba(44, 36, 32, 0.08);
    --shadow-lg: 0 8px 40px rgba(44, 36, 32, 0.12);

    /* Transitions */
    --transition-fast: 0.15s ease;
    --transition-normal: 0.3s ease;
    --transition-slow: 0.5s ease;

    /* Border Radius */
    --radius-sm: 6px;
    --radius-md: 12px;
    --radius-lg: 20px;
    --radius-xl: 32px;
}

/* Reset & Base Styles */
*, *::before, *::after {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
}

body {
    font-family: var(--font-body);
    font-size: 16px;
    line-height: 1.7;
    color: var(--color-text);
    background-color: var(--color-bg);
}

.container {
    max-width: var(--container-width);
    margin: 0 auto;
    padding: 0 2rem;
}

a {
    text-decoration: none;
    color: inherit;
}

ul {
    list-style: none;
}

img {
    max-width: 100%;
    display: block;
}

/* Typography */
h1, h2, h3, h4, h5 {
    font-family: var(--font-heading);
    font-weight: 600;
    line-height: 1.2;
}

h1 {
    font-size: clamp(2.75rem, 6vw, 4.5rem);
}

h2 {
    font-size: clamp(2rem, 4vw, 3rem);
}

h3 {
    font-size: clamp(1.25rem, 2vw, 1.5rem);
}

/* Section Tags */
.section-tag {
    display: inline-block;
    font-size: 0.875rem;
    font-weight: 500;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--color-accent);
    margin-bottom: 1rem;
}

.section-header {
    margin-bottom: 3.5rem;
}

.section-header h2 {
    margin-bottom: 1rem;
}

.section-header p {
    color: var(--color-text-light);
    max-width: 600px;
}

.section-header.centered {
    text-align: center;
}

.section-header.centered p {
    margin: 0 auto;
}

/* Buttons */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 1rem 2.25rem;
    font-size: 0.9375rem;
    font-weight: 500;
    border-radius: 100px;
    cursor: pointer;
    transition: var(--transition-normal);
    border: none;
    font-family: var(--font-body);
}

.btn-primary {
    background: var(--gradient-warm);
    color: var(--color-white);
    box-shadow: var(--shadow-md);
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: var(--shadow-lg);
}

.btn-secondary {
    background: transparent;
    color: var(--color-white);
    border: 2px solid var(--color-white);
}

.btn-secondary:hover {
    background: var(--color-white);
    color: var(--color-primary);
}

.btn-outline {
    background: transparent;
    color: var(--color-primary);
    border: 2px solid var(--color-primary);
}

.btn-outline:hover {
    background: var(--color-primary);
    color: var(--color-white);
}

.btn-full {
    width: 100%;
}

/* Logo */
.logo {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    font-family: var(--font-heading);
    font-size: 1.5rem;
    font-weight: 600;
    color: var(--color-primary);
}

.logo i {
    font-size: 1.75rem;
    color: var(--color-accent);
}

/* Navigation */
.navbar {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    z-index: 1000;
    background: rgba(255, 253, 248, 0.95);
    backdrop-filter: blur(20px);
    border-bottom: 1px solid var(--color-border);
    transition: var(--transition-normal);
}

.nav-container {
    max-width: var(--container-width);
    margin: 0 auto;
    padding: 1.25rem 2rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.nav-links {
    display: flex;
    align-items: center;
    gap: 2.5rem;
}

.nav-links a {
    font-size: 0.9375rem;
    font-weight: 500;
    color: var(--color-text);
    position: relative;
    transition: var(--transition-fast);
}

.nav-links a::after {
    content: '';
    position: absolute;
    bottom: -4px;
    left: 0;
    width: 0;
    height: 2px;
    background: var(--color-accent);
    transition: var(--transition-normal);
}

.nav-links a:hover::after,
.nav-links a.active::after {
    width: 100%;
}

.nav-links a:hover {
    color: var(--color-primary);
}

.nav-actions {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.cart-btn {
    position: relative;
    width: 44px;
    height: 44px;
    border-radius: 50%;
    border: none;
    background: var(--color-bg-alt);
    color: var(--color-text);
    cursor: pointer;
    transition: var(--transition-fast);
    display: flex;
    align-items: center;
    justify-content: center;
}

.cart-btn:hover {
    background: var(--color-primary);
    color: var(--color-white);
}

.cart-count {
    position: absolute;
    top: -2px;
    right: -2px;
    width: 18px;
    height: 18px;
    background: var(--color-accent);
    color: var(--color-white);
    font-size: 0.6875rem;
    font-weight: 600;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
}

.order-btn {
    padding: 0.75rem 1.5rem;
    background: var(--color-primary);
    color: var(--color-white);
    border: none;
    border-radius: 100px;
    font-size: 0.875rem;
    font-weight: 500;
    cursor: pointer;
    transition: var(--transition-fast);
}

.order-btn:hover {
    background: var(--color-primary-dark);
}

.mobile-menu-btn {
    display: none;
    flex-direction: column;
    gap: 5px;
    background: none;
    border: none;
    cursor: pointer;
    padding: 5px;
}

.mobile-menu-btn span {
    display: block;
    width: 25px;
    height: 2px;
    background: var(--color-text);
    transition: var(--transition-fast);
}

/* Hero Section */
.hero {
    position: relative;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    justify-content: center;
    padding: 8rem 2rem 4rem;
    overflow: hidden;
}

.hero-bg {
    position: absolute;
    inset: 0;
    background: var(--gradient-hero);
    z-index: -2;
}

.hero-bg::before {
    content: '';
    position: absolute;
    inset: 0;
    background: 
        radial-gradient(ellipse at 20% 50%, rgba(196, 167, 125, 0.15) 0%, transparent 50%),
        radial-gradient(ellipse at 80% 80%, rgba(196, 167, 125, 0.1) 0%, transparent 50%);
}

.hero-overlay {
    position: absolute;
    inset: 0;
    background: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E");
    opacity: 0.03;
    z-index: -1;
}

.hero-content {
    max-width: 800px;
    margin: 0 auto;
    text-align: center;
    color: var(--color-white);
}

.hero-tagline {
    display: inline-block;
    font-size: 0.875rem;
    font-weight: 500;
    text-transform: uppercase;
    letter-spacing: 3px;
    color: var(--color-accent);
    margin-bottom: 1.5rem;
}

.hero h1 {
    margin-bottom: 1.5rem;
}

.hero h1 .accent {
    color: var(--color-accent);
}

.hero p {
    font-size: 1.25rem;
    opacity: 0.9;
    margin-bottom: 2.5rem;
    max-width: 600px;
    margin-left: auto;
    margin-right: auto;
}

.hero-buttons {
    display: flex;
    gap: 1rem;
    justify-content: center;
    flex-wrap: wrap;
}

.hero-stats {
    display: flex;
    justify-content: center;
    gap: 4rem;
    margin-top: 5rem;
    padding-top: 3rem;
    border-top: 1px solid rgba(255, 255, 255, 0.1);
}

.stat-item {
    text-align: center;
    color: var(--color-white);
}

.stat-number {
    display: block;
    font-family: var(--font-heading);
    font-size: 2.5rem;
    font-weight: 700;
    color: var(--color-accent);
}

.stat-label {
    font-size: 0.875rem;
    opacity: 0.8;
    text-transform: uppercase;
    letter-spacing: 1px;
}

/* Features Section */
.features {
    padding: var(--section-padding) 0;
    background: var(--color-bg);
}

.features-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 2rem;
}

.feature-card {
    padding: 2.5rem;
    background: var(--color-white);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-sm);
    transition: var(--transition-normal);
    text-align: center;
}

.feature-card:hover {
    transform: translateY(-8px);
    box-shadow: var(--shadow-lg);
}

.feature-icon {
    width: 72px;
    height: 72px;
    margin: 0 auto 1.5rem;
    background: linear-gradient(135deg, var(--color-bg-alt) 0%, var(--color-white) 100%);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
}

.feature-icon i {
    font-size: 1.75rem;
    background: var(--gradient-warm);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.feature-card h3 {
    margin-bottom: 0.75rem;
    color: var(--color-primary);
}

.feature-card p {
    color: var(--color-text-light);
    font-size: 0.9375rem;
}

/* About Section */
.about {
    position: relative;
    padding: var(--section-padding) 0;
    background: var(--color-bg-alt);
    overflow: hidden;
}

.about-bg-text {
    position: absolute;
    top: 2rem;
    left: 2rem;
    font-family: var(--font-heading);
    font-size: clamp(8rem, 20vw, 16rem);
    font-weight: 700;
    color: transparent;
    -webkit-text-stroke: 1px var(--color-border);
    opacity: 0.5;
    user-select: none;
    line-height: 1;
}

.about-content {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 5rem;
    align-items: center;
    position: relative;
    z-index: 1;
}

.about-image {
    position: relative;
}

.image-frame {
    position: relative;
}

.about-img-placeholder {
    aspect-ratio: 4/5;
    background: linear-gradient(135deg, var(--color-primary) 0%, var(--color-primary-light) 100%);
    border-radius: var(--radius-xl);
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: var(--shadow-lg);
}

.about-img-placeholder i {
    font-size: 5rem;
    color: rgba(255, 255, 255, 0.3);
}

.about-img-placeholder::before {
    content: '';
    position: absolute;
    inset: 2rem;
    border: 2px dashed rgba(255, 255, 255, 0.2);
    border-radius: var(--radius-lg);
}

.experience-badge {
    position: absolute;
    bottom: 2rem;
    right: -1rem;
    background: var(--color-white);
    padding: 1.5rem 2rem;
    border-radius: var(--radius-md);
    box-shadow: var(--shadow-lg);
    text-align: center;
}

.experience-badge .years {
    display: block;
    font-family: var(--font-heading);
    font-size: 2rem;
    font-weight: 700;
    color: var(--color-primary);
    line-height: 1;
}

.experience-badge .text {
    font-size: 0.75rem;
    color: var(--color-text-light);
    text-transform: uppercase;
    letter-spacing: 1px;
}

.about-text h2 {
    margin-bottom: 1.5rem;
}

.about-text .lead {
    font-size: 1.125rem;
    color: var(--color-text);
    margin-bottom: 1.5rem;
}

.about-text p {
    color: var(--color-text-light);
    margin-bottom: 1.5rem;
}

.about-features {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
    margin-bottom: 2rem;
}

.about-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    font-size: 0.9375rem;
}

.about-item i {
    color: var(--color-accent);
    font-size: 1.125rem;
}

/* Menu Section */
.menu {
    position: relative;
    padding: var(--section-padding) 0;
    background: var(--color-bg);
}

.menu-pattern {
    position: absolute;
    inset: 0;
    background: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%236f4e37' fill-opacity='0.03'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
    opacity: 0.5;
}

.menu-tabs {
    display: flex;
    justify-content: center;
    gap: 1rem;
    margin-bottom: 3rem;
    flex-wrap: wrap;
}

.menu-tab {
    padding: 0.875rem 1.75rem;
    background: transparent;
    border: 2px solid var(--color-border);
    border-radius: 100px;
    font-size: 0.9375rem;
    font-weight: 500;
    color: var(--color-text-light);
    cursor: pointer;
    transition: var(--transition-fast);
}

.menu-tab:hover {
    border-color: var(--color-accent);
    color: var(--color-primary);
}

.menu-tab.active {
    background: var(--color-primary);
    border-color: var(--color-primary);
    color: var(--color-white);
}

.menu-content {
    min-height: 400px;
}

.menu-category {
    display: none;
}

.menu-category.active {
    display: block;
    animation: fadeIn 0.4s ease;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(10px); }
    to { opacity: 1; transform: translateY(0); }
}

.menu-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 1.5rem;
}

.menu-item {
    display: flex;
    gap: 1.5rem;
    padding: 1.5rem;
    background: var(--color-white);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-sm);
    transition: var(--transition-normal);
}

.menu-item:hover {
    box-shadow: var(--shadow-md);
    transform: translateX(5px);
}

.menu-item-image {
    flex-shrink: 0;
}

.menu-placeholder {
    width: 100px;
    height: 100px;
    background: linear-gradient(135deg, #F5EBE0 0%, #EDE0D4 100%);
    border-radius: var(--radius-md);
    display: flex;
    align-items: center;
    justify-content: center;
}

.menu-placeholder i {
    font-size: 2rem;
    color: var(--color-primary-light);
}

.menu-placeholder.cold {
    background: linear-gradient(135deg, #E3F2FD 0%, #BBDEFB 100%);
}

.menu-placeholder.cold i {
    color: #1976D2;
}

.menu-placeholder.tea {
    background: linear-gradient(135deg, #E8F5E9 0%, #C8E6C9 100%);
}

.menu-placeholder.tea i {
    color: #388E3C;
}

.menu-placeholder.pastry {
    background: linear-gradient(135deg, #FFF3E0 0%, #FFE0B2 100%);
}

.menu-placeholder.pastry i {
    color: #E65100;
}

.menu-placeholder.latte {
    background: linear-gradient(135deg, #D7CCC8 0%, #A1887F 100%);
}

.menu-placeholder.mocha {
    background: linear-gradient(135deg, #5D4037 0%, #3E2723 100%);
}

.menu-placeholder.mocha i {
    color: #D7CCC8;
}

.menu-placeholder.macchiato {
    background: linear-gradient(135deg, #FFECB3 0%, #FFC107 100%);
}

.menu-item-info {
    flex: 1;
}

.menu-item-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
}

.menu-item-header h4 {
    color: var(--color-primary);
}

.price {
    font-family: var(--font-heading);
    font-size: 1.25rem;
    font-weight: 600;
    color: var(--color-accent);
}

.menu-item-info > p {
    color: var(--color-text-light);
    font-size: 0.9375rem;
    margin-bottom: 0.75rem;
}

.badge {
    display: inline-block;
    padding: 0.25rem 0.75rem;
    background: #E8F5E9;
    color: #2E7D32;
    font-size: 0.75rem;
    font-weight: 600;
    border-radius: 100px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.badge.signature {
    background: #FFF3E0;
    color: #E65100;
}

.menu-footer {
    text-align: center;
    margin-top: 3rem;
    padding-top: 2rem;
    border-top: 1px solid var(--color-border);
}

.menu-footer p {
    color: var(--color-text-muted);
    font-size: 0.9375rem;
    margin-bottom: 1.5rem;
}

/* Gallery Section */
.gallery {
    padding: var(--section-padding) 0;
    background: var(--color-bg-alt);
}

.gallery-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    grid-template-rows: repeat(2, 280px);
    gap: 1.5rem;
}

.gallery-item {
    overflow: hidden;
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-md);
    transition: var(--transition-normal);
}

.gallery-item:hover {
    transform: scale(1.02);
    box-shadow: var(--shadow-lg);
}

.gallery-item.large {
    grid-column: span 2;
    grid-row: span 2;
}

.gallery-placeholder {
    width: 100%;
    height: 100%;
    background: linear-gradient(135deg, var(--color-primary) 0%, var(--color-primary-light) 100%);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 1rem;
}

.gallery-placeholder i {
    font-size: 3rem;
    color: rgba(255, 255, 255, 0.4);
}

.gallery-placeholder span {
    color: rgba(255, 255, 255, 0.8);
    font-size: 0.9375rem;
    font-weight: 500;
}

.gallery-item.large .gallery-placeholder i {
    font-size: 4rem;
}

.gallery-item.large .gallery-placeholder span {
    font-size: 1.125rem;
}

/* Testimonials Section */
.testimonials {
    padding: var(--section-padding) 0;
    background: var(--color-bg);
}

.testimonials-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 2rem;
}

.testimonial-card {
    padding: 2.5rem;
    background: var(--color-white);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-sm);
    transition: var(--transition-normal);
}

.testimonial-card:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow-lg);
}

.stars {
    display: flex;
    gap: 0.25rem;
    margin-bottom: 1.5rem;
}

.stars i {
    color: #FFB300;
    font-size: 0.875rem;
}

.testimonial-card > p {
    color: var(--color-text-light);
    font-size: 1rem;
    margin-bottom: 2rem;
    line-height: 1.8;
}

.testimonial-author {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.author-avatar {
    width: 50px;
    height: 50px;
    background: var(--gradient-warm);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--color-white);
    font-weight: 600;
    font-size: 0.875rem;
}

.author-info h5 {
    color: var(--color-primary);
    font-size: 1rem;
    margin-bottom: 0.25rem;
}

.author-info span {
    font-size: 0.875rem;
    color: var(--color-text-muted);
}

/* Contact Section */
.contact {
    padding: var(--section-padding) 0;
    background: var(--color-bg-alt);
}

.contact-grid {
    display: grid;
    grid-template-columns: 1fr 1fr 1.5fr;
    gap: 3rem;
}

.contact-info h2 {
    margin-bottom: 1rem;
}

.contact-info > p {
    color: var(--color-text-light);
    margin-bottom: 2rem;
}

.contact-details {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
    margin-bottom: 2rem;
}

.contact-item {
    display: flex;
    gap: 1rem;
}

.contact-item i {
    width: 44px;
    height: 44px;
    background: var(--color-white);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--color-accent);
    flex-shrink: 0;
